parameters.text:
=You are an Elite Tech & Finance Career Scout. Analyze the following news article:

Title: {{ $json.title }}
Description: {{ $json.description }}

Determine if this article contains information relevant to a student targeting a career in: AI/ML, Finance, Management Consulting, or Data Analytics (including internships, market trends, or major tech breakthroughs).

Respond with a raw, valid JSON object containing exactly two keys:
{
  "score": <integer from 1 to 10 evaluating career relevance>,
  "reason": "<a clear, 1-sentence explanation of your score>"
}
Do not write anything else. Do not wrap the code in markdown formatting block tags.

parameters.jsCode:
try {
  let aiText = $json.response.text;

  // Clean up code blocks if present
  aiText = aiText.replace(/```json|```/g, '').trim();

  // Isolate the pure JSON boundaries if the AI included conversational chatter
  const firstBracket = aiText.indexOf('{');
  const lastBracket = aiText.lastIndexOf('}');

  if (firstBracket !== -1 && lastBracket !== -1) {
    aiText = aiText.substring(firstBracket, lastBracket + 1);
  }

  const parsedAI = JSON.parse(aiText);

  return {
    title: $json.title,
    link: $json.link,
    description: $json.description,
    score: Number(parsedAI.score || 0),
    reason: parsedAI.reason || "No reason provided."
  };
} catch (error) {
  // Safe fallback if the specific payload run completely failed structural parsing
  return {
    title: $json.title,
    link: $json.link,
    description: $json.description,
    score: 1,
    reason: "Failed parsing response format cleanly."
  };
}

// Get all incoming raw articles
const articles = $input.all();

// Grab only the first 5 articles to respect Discord's length limits
const topArticles = articles.slice(0, 5);

let messageBody = "📅 **YOUR DAILY RAW TECHCRUNCH BRIEF** 📅\n";
messageBody += "=========================================\n\n";

for (const item of topArticles) {
  const data = item.json;

  const title = data.title || "No Title Available";
  const link = data.link || "#";
  // Grab just the first 120 characters of the description to save space
  let desc = data.description || "No description available.";
  desc = desc.replace(/<[^>]*>/g, '').trim(); // Strip HTML tags
  if (desc.length > 120) desc = desc.substring(0, 120) + "...";

  // Build the clean item block
  messageBody += `📢 **${title}**\n`;
  messageBody += `📝 ${desc}\n`;
  messageBody += `🔗 ${link}\n\n`;
  messageBody += "-----------------------------------------\n\n";
}

// Final safety check: if somehow it's still over 1900 chars, hard crop it
if (messageBody.length > 1900) {
  messageBody = messageBody.substring(0, 1850) + "\n\n...[Truncated due to length limits]";
}

return {
  content: messageBody
};
